"""Connecteur SERP API â€” HasData et Serpstack.

Deux fournisseurs supportÃ©s avec fallback automatique.
"""

from typing import Optional

import httpx

from hermes import config
from hermes.core.exceptions import SerpAPIError


class SerpAPIClient:
    """Client unifiÃ© pour les APIs SERP."""

    def __init__(self, dry_run: bool = False):
        self.dry_run = dry_run

    async def search(self, keyword: str, location: str = "fr", language: str = "fr") -> dict:
        """RÃ©cupÃ¨re les donnÃ©es SERP pour un mot-clÃ©.

        PrioritÃ© : HasData > Serpstack.
        """
        if self.dry_run:
            return self._mock_response(keyword)

        if config.HASDATA_API_KEY:
            return await self._search_hasdata(keyword, location, language)
        elif config.SERPSTACK_API_KEY:
            return await self._search_serpstack(keyword, location, language)
        else:
            raise SerpAPIError(
                "Aucune API SERP configurÃ©e. DÃ©finissez HASDATA_API_KEY ou SERPSTACK_API_KEY "
                "dans .env, ou utilisez --dry-run."
            )

    async def _search_hasdata(self, keyword: str, location: str, language: str) -> dict:
        """Appelle l'API HasData."""
        async with httpx.AsyncClient(timeout=30.0) as client:
            resp = await client.get(
                "https://api.hasdata.com/v1/serp/google",
                params={
                    "key": config.HASDATA_API_KEY,
                    "q": keyword,
                    "location": location,
                    "language": language,
                },
            )
            resp.raise_for_status()
            data = resp.json()
            if data.get("error"):
                raise SerpAPIError(f"HasData error: {data['error']}")
            return data

    async def _search_serpstack(self, keyword: str, location: str, language: str) -> dict:
        """Appelle l'API Serpstack."""
        async with httpx.AsyncClient(timeout=30.0) as client:
            resp = await client.get(
                "http://api.serpstack.com/search",
                params={
                    "access_key": config.SERPSTACK_API_KEY,
                    "query": keyword,
                    "gl": location,
                    "hl": language,
                },
            )
            resp.raise_for_status()
            data = resp.json()
            if data.get("error"):
                raise SerpAPIError(f"Serpstack error: {data['error']}")
            return data

    def _mock_response(self, keyword: str) -> dict:
        """RÃ©ponse simulÃ©e pour le mode dry-run."""
        return {
            "keyword": keyword,
            "organic_results": [
                {
                    "position": i,
                    "title": f"RÃ©sultat simulÃ© #{i} pour {keyword}",
